// Validate incoming unit payload
const body = $input.first().json.body || $input.first().json;

const required = ['unit_url', 'sale_price_thb', 'bedrooms', 'province'];
const missing = required.filter(f => !body[f]);

if (missing.length > 0) {
  return [{
    json: {
      valid: false,
      error: `Missing required fields: ${missing.join(', ')}`,
      body
    }
  }];
}

// Normalize
const unit = {
  unit_url: body.unit_url,
  unit_id: body.unit_id || String(body.unit_url).match(/u(\d+)$/)?.[1] || '',
  project_name: body.project_name || '',
  project_url: body.project_url || '',
  sale_price_thb: parseInt(body.sale_price_thb),
  price_per_sqm_thb: body.price_per_sqm_thb ? parseInt(body.price_per_sqm_thb) : null,
  bedrooms: body.bedrooms,
  bathrooms: body.bathrooms,
  floor_area_sqm: body.floor_area_sqm ? parseFloat(body.floor_area_sqm) : null,
  plot_size_sqm: body.plot_size_sqm ? parseFloat(body.plot_size_sqm) : null,
  floor_number: body.floor_number ? parseInt(body.floor_number) : null,
  property_type: body.property_type || 'condo',
  ownership: body.ownership || null,
  furnishing: body.furnishing || null,
  view_type: body.view_type || null,
  district: body.district || null,
  subdistrict: body.subdistrict || null,
  province: body.province,
  latitude: body.latitude ? parseFloat(body.latitude) : null,
  longitude: body.longitude ? parseFloat(body.longitude) : null,
  features: Array.isArray(body.features) ? body.features : [],
  images: Array.isArray(body.images) ? body.images : [],
  developer: body.developer || null,
  construction_status: body.construction_status || null,
  nearest_landmark: body.nearest_landmark || null,
  building_name: body.building_name || null,
  listed_by: body.listed_by || null,
  cam_fee_thb: body.cam_fee_thb ? parseInt(body.cam_fee_thb) : null,
  data_quality_score: body.data_quality_score || 70,
  scraped_at: body.scraped_at || new Date().toISOString(),
  source: body.source || 'webhook'
};

return [{ json: { valid: true, unit } }];
